class capture:

    def book(self):
        win = tkinter.Tk()
        win.title('Strontium')
        win.geometry('390x250+300+200')
        win.resizable(0,0)

        status = tkinter.StringVar()
        status.set('명령어를 입력하십시오') #상태표시
        label0 = tkinter.Label(win, textvariable = status, font=("Consolas", 15))
        label0.place(x=5,y=5)

        orders = [ ] #명령어들
        listbox = tkinter.Listbox(win, width=20, height=5, font=("Consolas", 15))
        listbox.place(x=5,y=50)

        in0 = tkinter.Entry(width=20, font=("Consolas", 15))
        in0.grid(column = 0 , row = 0)
        in0.place(x=5,y=210) #명령어 입력창

        in1 = tkinter.Entry(width=5, font=("Consolas", 15))
        in1.grid(column = 0 , row = 0)
        in1.place(x=300,y=5) #반복수 입력창

        def lock(): #화면 잠금
            time.sleep(0.1)
            nonlocal locked
            nonlocal but0
            nonlocal win
            if locked:
                locked = False
                but0.configure(bg='gray95')
                win.wm_attributes("-topmost", 0)
            else:
                locked = True
                but0.configure(bg='lawn green')
                win.wm_attributes("-topmost", 1)
        but0 = tkinter.Button(win, text = 'L', font=("Consolas", 15), command = lock, bg = 'gray95')
        but0.place(x = 300,y = 45)
        locked = False

        def go():
            time.sleep(0.1)
            nonlocal win
            nonlocal orders
            nonlocal in1
            nonlocal status
            try:
                num = int( in1.get() ) #반복수
                status.set( '반복수' + str(num) + ' 명령수' + str( len(orders) ) )
                win.update()
                time.sleep(0.7)
            except Exception as e:
                num = 0
                status.set( 'STE/' + str(e)[0:15] )
                win.update()
                time.sleep(0.7)
            status.set( '작업 시작' )
            try:
                shutil.rmtree('temp345')
            except:
                pass
            os.mkdir('temp345')
            scr = 0 #스크린샷 넘버링
            for i in range(0,num):
                for j in orders:
                    args = j.split(' ') #띄어쓰기 분할
                    status.set( args[0] + ' at ' + str(i) )
                    win.update()
                    time.sleep(0.1)
                    try:
                        if args[0] == 'sleep':
                            time.sleep( float( args[1] ) )
                        elif args[0] == 'capture':
                            if args[1] == 'all':
                                pyautogui.screenshot(f'temp345\\pic{scr}.png')
                            else:
                                pyautogui.screenshot( f'temp345\\pic{scr}.png',
                                                      region=( int(args[1]), int(args[2]), int(args[3])-int(args[1]), int(args[4])-int(args[2]) ) )
                            scr = scr + 1
                        elif args[0] == 'moveto':
                            pyautogui.moveTo( int(args[1]), int(args[2]), 0.1 )
                        elif args[0] == 'click':
                            for k in range(0,int(args[1])):
                                pyautogui.click()
                                time.sleep(0.2)
                        elif args[0] == 'scroll':
                            pyautogui.scroll( int(args[1]) )
                    except Exception as e:
                        print(e)
            status.set( '작업 완료' )
            os.startfile('temp345')
        but1 = tkinter.Button(win, text = 'G', font=("Consolas", 15), command = go)
        but1.place(x = 340,y = 45) #실행 버튼

        def inf():
            time.sleep(0.1)
            file = filedialog.askopenfile( title='명령어 텍스트 파일 선택', filetypes=( ('all files', '*.*'), ('txt files', '*.txt') ) )
            path = file.name #txt path
            with open(path,'r',encoding='utf-8') as f:
                txt = f.readlines() #\n으로 끝나는 문자열들의 리스트
            txt = [ i[0:-1] for i in txt ] #\n delete
            nonlocal orders
            nonlocal listbox
            listbox.delete( 0,listbox.size() )
            orders = txt
            for i in txt:
                listbox.insert( listbox.size(),i )
        but2 = tkinter.Button(win, text = '↓', font=("Consolas", 15), command = inf)
        but2.place(x = 300,y = 100) #가져오기

        def outf():
            time.sleep(0.1)
            nonlocal orders
            with open('data345.txt','w',encoding='utf-8') as f:
                for i in orders:
                    f.write(i+'\n')
            os.startfile('data345.txt')
        but3 = tkinter.Button(win, text = '↑', font=("Consolas", 15), command = outf)
        but3.place(x = 340,y = 100) #내보내기

        def addf():
            time.sleep(0.1)
            nonlocal orders
            nonlocal listbox
            nonlocal in0
            txt = in0.get()
            orders.append(txt)
            listbox.insert( listbox.size(),txt )
        but4 = tkinter.Button(win, text = 'O', font=("Consolas", 15), command = addf)
        but4.place(x = 300,y = 155) #추가

        def delf():
            time.sleep(0.1)
            nonlocal orders
            nonlocal listbox
            orders = orders[0:-1]
            listbox.delete( listbox.size()-1,listbox.size() )
        but5 = tkinter.Button(win, text = 'X', font=("Consolas", 15), command = delf)
        but5.place(x = 340,y = 155) #삭제

        def helpf():
            time.sleep(0.1)
            tkinter.messagebox.showinfo('도움말',''' GUI 설명 : 반복수 / 창 잠금 / 실행 / 가져오기 / 내보내기 / 추가 / 삭제
명령어 설명 : sleep N / capture all / capture N N N N / moveto N N / click N / scroll N ''')
        but6 = tkinter.Button(win, text = 'h e l p', font=("Consolas", 10), command = helpf)
        but6.place(x = 300,y = 210) #삭제

        win.mainloop()

